impl Solution { pub fn place_word_in_crossword(black_b: Vec<Vec<char>>, black_w: String) -> bool { let (black_m, black_n) = (black_b.len(), black_b[0].len()); let black_v = black_w.chars().collect::<Vec<_>>(); let black_rv = black_w.chars().rev().collect::<Vec<_>>(); let mut black_boards = vec![black_b.clone()]; let mut black_t = vec![vec![' '; black_m]; black_n]; for i in 0..black_m { for j in 0..black_n { black_t[j][i] = black_b[i][j]; } } black_boards.push(black_t); for black_bd in black_boards { for row in black_bd { for part in row.iter().collect::<String>().split('#') { if part.len() == black_v.len() { if part.chars().enumerate().all(|(i, c)| c == ' ' || c == black_v[i]) || part.chars().enumerate().all(|(i, c)| c == ' ' || c == black_rv[i]) { return true; } } } } } false } }